// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if(g_form.getValue('u_ou_parent') + '' != ''){
		var isNewRecord = g_form.isNewRecord();

		// not sure why, but u_ou_parent isn't loaded when this fires
		g_form.removeOption('u_request_type','Clarification');
		g_form.removeOption('u_request_type','Extension');
		g_form.removeOption('u_request_type','Reassignment');
		setRequestRecipients(g_form.getValue('u_ou_parent'));

		var status = g_form.getValue('u_status');
		if (isNewRecord == true){
			g_form.setDisplay('u_status', false);
		}
		if (isNewRecord != true){ 
			g_form.setReadOnly('u_request_comments', true);
			g_form.setReadOnly('u_response_comments', false);
		}

		if (status == "In progress"){
			g_form.setMandatory("u_response_comments", true);
		}

		if (status == "Completed"){
			g_form.setReadOnly("u_request_comments", true);
			g_form.setReadOnly("u_response_comments", true);
		}
	}

	function setRequestRecipients(OUID){
		var requestRecipients = '';
		var requestRecipientDisplayValues = '';
		if(g_form.getValue('u_ou_parent.u_ou_hierarchy_administrators')){
			requestRecipients = g_form.getValue('u_ou_parent.u_ou_hierarchy_administrators');
			g_form.setValue('u_request_recipients', requestRecipients);
			// if found, no reason to look any further
			return;
		}

		var ga = new GlideAjax("ClientOrganizationalScripts");
		ga.addParam('sysparm_name', 'getOUHA_responsible');
		ga.addParam('sysparam_OUID',OUID);
		ga.getXML(function(response){
			var answer = response.responseXML.documentElement.getAttribute("answer");
			var OUHA_responsible = JSON.parse(answer);
			if(OUHA_responsible.Administrators.value){
				requestRecipients = OUHA_responsible.Administrators.value;
				requestRecipientDisplayValues = OUHA_responsible.Administrators.displayValue;
			} else if (OUHA_responsible.GlobalAdministrators.value){
				requestRecipients = OUHA_responsible.GlobalAdministrators.value;
				requestRecipientDisplayValues = OUHA_responsible.GlobalAdministrators.displayValue;
			} 
			g_form.setValue('u_request_recipients', requestRecipients, requestRecipientDisplayValues);
		});
	}
}
